// Filter out MEMORY.md (too large) and prepare items
const files = $input.first().json.files.filter(f => f.name !== 'MEMORY.md');
return files.map(f => ({ json: { fileId: f.id, fileName: f.name } }));

const allResults = $input.all().map(item => item.json);
const today = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric' });
const changedCount = allResults.filter(r => r.changed).length;

const detailsHtml = allResults.map(r => {
  const changesHtml = (r.changes && r.changes !== 'No changes')
    ? `<p><b>Changes:</b></p><ul>${r.changes.split('\n').filter(Boolean).map(l => `<li>${l.replace(/^[-\u2022\s]+/, '')}</li>`).join('')}</ul>`
    : `<p><i>No changes</i></p>`;
  const obsHtml = r.observation ? `<p><b>Observation:</b> ${r.observation}</p>` : '';
  const badge = r.changed ? ' <span style="color:green">[updated]</span>' : '';
  return `<h3>${r.fileName}${badge}</h3>${changesHtml}${obsHtml}`;
}).join('<hr>');

const subject = changedCount > 0
  ? `🧠 Autodream - ${changedCount} file(s) updated - ${today}`
  : `🧠 Autodream - Memory report - ${today}`;

const body = `<h2>Autodream — Memory Consolidation Report</h2><p><b>Date:</b> ${today}</p><p>${changedCount > 0 ? changedCount + ' file(s) updated' : 'No changes needed'}</p><h3>File details</h3>${detailsHtml}`;

return [{ json: { subject, body } }];
